mapper.update:
update service_item
category_id=#{categoryId}, name=#{name}, price=#{price}, description=#{description}, duration_minutes=#{durationMinutes}, status=#{status}, update_time=#{updateTime},
where id=#{id}

mapper.select:
select si.*,sc.name as categoryName from service_item si left join service_category sc on si.category_id=sc.id
si.status=1
and si.category_id=#{categoryId}
